"use strict";const header=document.getElementById("header"),intro=document.querySelector(".intro");if(header&&intro){function e(){let e=intro.offsetHeight,t=window.scrollY;header.classList.toggle("fixed",t>e)}e(),window.addEventListener("scroll",e),window.addEventListener("resize",e)}const burger=document.getElementById("burger"),menu=document.getElementById("menu");burger.addEventListener("click",()=>{burger.classList.toggle("active"),menu.classList.toggle("active"),menu.classList.contains("active")?(document.documentElement.style.overflow="hidden",document.body.style.overflow="hidden"):(document.documentElement.style.overflow="",document.body.style.overflow="");let e=document.querySelectorAll(".menu-link");e.forEach(e=>{e.addEventListener("click",()=>{burger.classList.remove("active"),menu.classList.remove("active"),document.documentElement.style.overflow="",document.body.style.overflow=""})})}),$(document).ready(function(){$(".reviews-inner").slick({dots:!0,infinite:!0,speed:300,slidesToShow:2,slidesToScroll:1,autoplay:!0,autoplaySpeed:1500,accessibility:!1,responsive:[{breakpoint:1024,settings:{slidesToShow:2,slidesToScroll:1,infinite:!0}},{breakpoint:768,settings:{slidesToShow:1,slidesToScroll:1,infinite:!0}},]})});